let score = 85

if score >= 90 {
    print("Grade: A")
} else if score >= 80 {
    print("Grade: B")
} else if score >= 70 {
    print("Grade: C")
} else {
    print("Grade: F")
}

let day = "Monday"
switch day {
case "Saturday", "Sunday":
    print("Weekend!")
default:
    print("Weekday: \(day)")
}
